let _fromCtx: FromContext | null = null;
function getFromContext(): FromContext {
  if (_fromCtx) return _fromCtx;
  _fromCtx = {
    getFields: (k) => FROM_FIELD_TYPES[k],
    getChildrenTypes: (k) => FROM_CHILDREN_TYPES[k],
    isLeaf: (k) => FROM_LEAF_SET.has(k),
    isBranch: (k) => FROM_BRANCH_SET.has(k),
    getLeafValues: (k) => FROM_LEAF_VALUES[k],
    createLeaf: (kind, text) => {
      const f = FROM_LEAF_FACTORIES[kind];
      if (!f) throw new Error(`No leaf factory for kind '${kind}'`);
      return f(text);
    },
    createBranch: (kind, config) => {
      const f = FROM_BRANCH_FACTORIES[kind];
      if (!f) throw new Error(`No branch factory for kind '${kind}'`);
      return f(config);
    },
  };
  return _fromCtx;
}

